 std::optional<std::pair<CmpPredicate, Constant *>>
 llvm::getFlippedStrictnessPredicateAndConstant(CmpPredicate Pred, Constant *C) {
+  auto *CI = dyn_cast<ConstantInt>(C);
+  if (!CI)
+    return None;
+  APInt Val = CI->getValue();
+  unsigned BW = Val.getBitWidth();
+
+  switch (Pred) {
+  case ICmpInst::ICMP_SGE: {
+    // x sge K -> x sgt K-1 (signed-aware), saturate at SMin
+    if (Val == APInt::getSignedMinValue(BW))
+      return std::make_pair(ICmpInst::ICMP_SGE, C);
+    APInt Adj = Val - 1;
+    return std::make_pair(ICmpInst::ICMP_SGT, ConstantInt::get(CI->getType(), Adj));
+  }
+  case ICmpInst::ICMP_SLE: {
+    // x sle K -> x slt K+1 (signed-aware), saturate at SMax
+    if (Val == APInt::getSignedMaxValue(BW))
+      return std::make_pair(ICmpInst::ICMP_SLE, C);
+    APInt Adj = Val + 1;
+    return std::make_pair(ICmpInst::ICMP_SLT, ConstantInt::get(CI->getType(), Adj));
+  }
+  case ICmpInst::ICMP_UGE: {
+    // x uge K -> x ugt K-1 (unsigned-aware), saturate at UMin
+    if (Val.isMinValue())
+      return std::make_pair(ICmpInst::ICMP_UGE, C);
+    APInt Adj = Val - 1;
+    return std::make_pair(ICmpInst::ICMP_UGT, ConstantInt::get(CI->getType(), Adj));
+  }
+  case ICmpInst::ICMP_ULE: {
+    // x ule K -> x ult K+1 (unsigned-aware), saturate at UMax
+    if (Val.isMaxValue())
+      return std::make_pair(ICmpInst::ICMP_ULE, C);
+    APInt Adj = Val + 1;
+    return std::make_pair(ICmpInst::ICMP_ULT, ConstantInt::get(CI->getType(), Adj));
+  }
+  default:
+    return None;
+  }
+}
